using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator" — preserve for compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9: id values no longer include discriminator prefix.
            // Existing documents have format "Product|123" — preserve for compatibility.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // REMOVED: HasIndex throws in EF Core 9 Cosmos provider.
        // Cosmos DB indexing is managed via the container's indexing policy.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } = null!; }

